// Initialize the WebDriver
driver = await new Builder().forBrowser('chrome').build();
// Define system variables
const url =  "https://gtam.gtls.store";
const mainUrl = 'gtam';
// Call the login helper function
await loginToApp(driver, url, mainUrl);

